import type { Question, QuestionMedia } from '../../../core/models';

/**
 * « Image mystère » — personnages de manga / anime et de jeux vidéo.
 *
 * Gros volume d'images de personnages, tous niveaux. Sources d'images :
 *  - Manga / anime : l'artwork de fiche personnage de MyAnimeList
 *    (cdn.myanimelist.net). URLs plutôt stables, mais si l'une change ou tombe,
 *    la question est automatiquement remplacée en jeu (même joueur, +1 au
 *    total) et l'écran « Vérifier les images » la signale.
 *  - Jeux vidéo : rendus d'amiibo Nintendo hébergés sur GitHub (fiables) et
 *    artwork officiel des Pokémon via PokeAPI (fiable).
 *
 * Généré : les propositions d'une question ont toutes le même nombre de mots
 * (nom homogène : soit un seul nom, soit prénom + nom pour toutes), et les
 * distracteurs sont de notoriété comparable. Aucune parenthèse.
 */

/** Fiche personnage MyAnimeList (URL complète). */
const mal = (url: string): QuestionMedia => ({ type: 'image', uri: url });

/** Rendu d'un amiibo hébergé sur GitHub (personnages Nintendo & invités). */
const amiibo = (icon: string): QuestionMedia => ({
  type: 'image',
  uri: `https://raw.githubusercontent.com/N3evin/AmiiboAPI/master/images/${icon}`,
});

/** Artwork officiel d'un Pokémon par numéro national (PokeAPI, hébergé GitHub). */
const poke = (n: number): QuestionMedia => ({
  type: 'image',
  uri: `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/${n}.png`,
});

const MANGA_PERSO = 'Quel personnage de manga est-ce ?';
const JV_PERSO = 'Quel personnage de jeu vidéo est-ce ?';
const POKE = 'Quel est ce Pokémon ?';

